  4	import useKubevirtUserSettingsTableColumns from '@kubevirt-utils/hooks/useKubevirtUserSettings/useKubevirtUserSettingsTableColumns';
  5	import { ColumnLayout } from '@openshift-console/dynamic-plugin-sdk';
  6	import {
  7	  ActionList,
  8	  ActionListItem,
  9	  Alert,
 10	  AlertVariant,
 11	  Button,
 12	  ButtonVariant,
 13	  DataList,
 14	  Modal,
 15	  ModalVariant,
 16	  Stack,
 17	  StackItem,
 18	} from '@patternfly/react-core';
 19	
 20	import { MAX_VIEW_COLS } from './constants';
 21	import DataListRow from './DataListRow';
 22	import { createInputId, getColumnId } from './utils';
 23	
 24	import './column-management-modal.scss';
 25	
 26	type ColumnManagementModalProps = {
 27	  columnLayout: ColumnLayout;
 28	  isOpen: boolean;
 29	  onClose: () => void;
 30	};
 31	
 32	export const ColumnManagementModal: FC<ColumnManagementModalProps> = ({
 33	  columnLayout,
 34	  isOpen,
 35	  onClose,
 36	}) => {
 37	  const { t } = useKubevirtTranslation();
 38	  const { columns, id, selectedColumns, showNamespaceOverride, type } = columnLayout;
 39	
 40	  const defaultColumns = columns.filter((column) => column.id && !column.additional);
 41	  const additionalColumns = columns.filter((column) => column.additional);
 42	
 43	  const [_, setActiveColumns, loaded, error] = useKubevirtUserSettingsTableColumns({
 44	    columnManagementID: id,
 45	    columns,
 46	  });
 47	
 48	  const [checkedColumns, setCheckedColumns] = useState<Set<string>>(
 49	    selectedColumns && selectedColumns.size !== 0
 50	      ? new Set(selectedColumns)
 51	      : new Set(defaultColumns.map((col) => col.id)),
 52	  );
 53	
 54	  const onColumnChange = (event: FormEvent<HTMLInputElement>): void => {
 55	    const updatedCheckedColumns = new Set<string>(checkedColumns);
 56	    const selectedId = getColumnId(event?.currentTarget?.id);
 57	    updatedCheckedColumns.has(selectedId)
 58	      ? updatedCheckedColumns.delete(selectedId)
 59	      : updatedCheckedColumns.add(selectedId);
 60	    setCheckedColumns(updatedCheckedColumns);
 61	  };
 62	
 63	  const submit: MouseEventHandler<HTMLButtonElement> = async (event) => {
 64	    event.preventDefault();
 65	    const orderedCheckedColumns = new Set<string>();
 66	    checkedColumns.forEach((ids) => orderedCheckedColumns.add(ids));
 67	
 68	    await setActiveColumns([...orderedCheckedColumns]);
 69	    onClose();
 70	  };
 71	
 72	  const areMaxColumnsDisplayed = checkedColumns.size >= MAX_VIEW_COLS;
 73	
 74	  const resetColumns = (event: SyntheticEvent): void => {
 75	    event.preventDefault();
 76	    const updatedCheckedColumns = new Set(checkedColumns);
 77	    defaultColumns.forEach((col) => col.id && updatedCheckedColumns.add(col.id));
 78	    additionalColumns.forEach((col) => updatedCheckedColumns.delete(col.id));
 79	    setCheckedColumns(updatedCheckedColumns);
 80	  };
 81	
 82	  return (
 83	    <Modal
 84	      footer={
 85	        <Stack className="kv-tabmodal-footer" hasGutter>
 86	          {error && (
 87	            <StackItem>
 88	              <Alert isInline title={t('An error occurred')} variant={AlertVariant.danger}>
 89	                <Stack hasGutter>
 90	                  <StackItem>{error.message}</StackItem>
 91	                </Stack>
 92	              </Alert>
 93	            </StackItem>
 94	          )}
 95	          <StackItem>
 96	            <ActionList className="column-management-modal__action-list">
 97	              <ActionListItem>
 98	                <Button key="reset" onClick={resetColumns} variant={ButtonVariant.link}>
 99	                  {t('Restore default columns')}
100	                </Button>
101	              </ActionListItem>
102	
103	              <ActionListItem>
104	                <Button onClick={onClose} variant={ButtonVariant.secondary}>
105	                  {t('Cancel')}
106	                </Button>
107	              </ActionListItem>
108	              <ActionListItem>
109	                <Button
110	                  form="modal-with-form-form"
111	                  isDisabled={!loaded}
112	                  isLoading={!loaded}
113	                  key="create"
114	                  onClick={submit}
115	                  variant={ButtonVariant.primary}
116	                >
117	                  {t('Save')}
118	                </Button>
119	              </ActionListItem>
120	            </ActionList>
121	          </StackItem>
122	        </Stack>
123	      }
124	      isOpen={isOpen}
125	      onClose={onClose}
126	      position="top"
127	      title={t('Manage columns')}
128	      variant={ModalVariant.small}
129	    >
130	      <>
131	        <p className="co-m-form-row">{t('Selected columns will appear in the table.')}</p>
132	        <Alert
133	          className="co-alert"
134	          isInline
135	          title={t('You can select up to {{MAX_VIEW_COLS}} columns', { MAX_VIEW_COLS })}
136	          variant={AlertVariant.info}
137	        >
138	          {!showNamespaceOverride && t('The namespace column is only shown when in "All projects"')}
139	        </Alert>
140	        <div className="row co-m-form-row">
141	          <div className="col-sm-12">
142	            <span className="col-sm-6">
143	              <label className="control-label">
144	                {t('Default {{resourceKind}} columns', { resourceKind: type })}
145	              </label>
146	              <DataList
147	                aria-label={t('Default column list')}
148	                id="defalt-column-management"
149	                isCompact
150	              >
151	                {defaultColumns.map((defaultColumn) => (
152	                  <DataListRow
153	                    checkedColumns={checkedColumns}
154	                    column={defaultColumn}
155	                    disableUncheckedRow={areMaxColumnsDisplayed}
156	                    inputId={createInputId(defaultColumn.id)}
157	                    key={defaultColumn.id}
158	                    onChange={onColumnChange}
159	                  />
160	                ))}
161	              </DataList>
162	            </span>
163	            <span className="col-sm-6">
164	              <label className="control-label">{t('Additional columns')}</label>
165	              <DataList
166	                aria-label={t('Additional column list')}
167	                id="additional-column-management"
168	                isCompact
169	              >
170	                {additionalColumns.map((additionalColumn) => (
171	                  <DataListRow
172	                    checkedColumns={checkedColumns}
173	                    column={additionalColumn}
174	                    disableUncheckedRow={areMaxColumnsDisplayed}
175	                    inputId={createInputId(additionalColumn.id)}
176	                    key={additionalColumn.id}
177	                    onChange={onColumnChange}
178	                  />
179	                ))}
180	              </DataList>
181	            </span>
182	          </div>
183	        </div>
184	      </>
185	    </Modal>
186	  );
187	};

